package com.hospital.management.controller.schedule;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DoctorScheduleServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/schedules/edit")public class DoctorScheduleEditServlet extends HttpServlet{private final DoctorScheduleService service;public DoctorScheduleEditServlet(){this(new DoctorScheduleServiceImpl());}public DoctorScheduleEditServlet(DoctorScheduleService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=ScheduleRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}DoctorSchedule x=service.getSchedule(id).orElse(null);if(x==null){r.sendError(404);return;}if(!service.canAccess(x,ScheduleRequest.user(q))){r.sendError(403);return;}show(q,r,ScheduleRequest.form(x));}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=ScheduleRequest.id(q.getParameter("scheduleId"));if(id==null){r.sendError(400);return;}DoctorScheduleForm f=ScheduleRequest.form(q,id);ServiceResult<Void>x=service.updateSchedule(f,RequestUtil.buildAuditContext(q),ScheduleRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/schedules?message=updated");return;}if(x.getStatus()==ServiceResult.Status.NOT_FOUND){r.sendError(404);return;}if(x.getStatus()==ServiceResult.Status.FORBIDDEN){r.sendError(403);return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,DoctorScheduleForm f)throws ServletException,IOException{AuthenticatedUser u=ScheduleRequest.user(q);q.setAttribute("formMode","EDIT");q.setAttribute("scheduleForm",f);q.setAttribute("doctors",service.getActiveDoctors());if("DOCTOR".equals(u.getRoleName()))q.setAttribute("ownDoctor",service.getOwnDoctor(u).orElse(null));q.getRequestDispatcher("/WEB-INF/views/schedules/form.jsp").forward(q,r);}}
